   242→
   243→# RSA key generation could be very slow without compilation
   244→# optimizations, in development mode. Without optimizations, WPT might
   245→# consider RSA key generation tests fail due to timeout.
   246→# Building with higher optimization levels can speed up the key
   247→# generation process to avoid false negative result in those tests.
   248→# More details: <https://docs.rs/rsa/0.9.8/rsa/index.html#example>
   249→[profile.dev.package.num-bigint-dig]
   250→opt-level = 3
   251→
   252→# Force tikv-jemalloc-sys to build with at least -O1.
   253→# This can help with build environments that force _FORTIFY_SOURCE, such as Nix.
   254→# More details: <https://github.com/tikv/jemallocator/issues/108>
   255→[profile.dev.package.tikv-jemalloc-sys]
   256→opt-level = 1
   257→
   258→[profile.release]
   259→opt-level = 3
   260→debug-assertions = true
   261→
   262→# Disk-space is limited in CI, so we disabled features that are not needed for code coverage.
   263→# Locally using the default `dev` profile is perfectly fine.
   264→[profile.coverage]
   265→inherits = "dev"
   266→incremental = false
   267→debug = false
   268→
   269→# A profile between `dev` and `release` which aims to offer a compromise between
   270→# fast incremental rebuilds and runtime speed.
   271→[profile.medium]
   272→inherits = "release"
   273→opt-level = 2
   274→incremental = true
   275→debug = "line-tables-only"
   276→
   277→[profile.production]
   278→inherits = "release"
   279→debug-assertions = false
   280→lto = true
   281→codegen-units = 1
   282→opt-level = "s"
   283→
   284→[profile.production-stripped]
   285→inherits = "production"
   286→strip = true
   287→
   288→[profile.profiling]
   289→inherits = "release"
   290→debug-assertions = false
   291→debug = true
   292→lto = "thin"
   293→codegen-units = 1
   294→
   295→[patch.crates-io]
   296→# If you need to temporarily test Servo with a local fork of some upstream
   297→# crate, add that here. Use the form:
   298→#
   299→#     <crate> = { path = "/path/to/local/checkout" }
   300→#
   301→# For html5ever:
   302→#
   303→# html5ever = { path = "../html5ever/html5ever" }
   304→# markup5ever = { path = "../html5ever/markup5ever" }
   305→# web_atoms = { path = "../html5ever/web_atoms" }
   306→# xml5ever = { path = "../html5ever/xml5ever" }
   307→# tendril = { path = "../html5ever/tendril" }
   308→#
   309→# Or for mozjs:
   310→#
   311→# mozjs = { path = "../mozjs/mozjs" }
   312→# mozjs_sys = { path = "../mozjs/mozjs-sys" }
   313→#
   314→# Pending egui bumping their accesskit version: https://github.com/emilk/egui/pull/7850
   315→# This is only used in servoshell.
   316→# TODO: When these are no longer needed remove the exception in deny.toml as well.
   317→egui = { git = "https://github.com/emilk/egui.git", rev = "5d8f393335e051785b4fd3af9ef92eda5b61177f" }
   318→egui-winit = { git = "https://github.com/emilk/egui.git", rev = "5d8f393335e051785b4fd3af9ef92eda5b61177f" }
   319→#
   320→# Or for Stylo:
   321→#
   322→# [patch."https://github.com/servo/stylo"]
   323→# selectors = { path = "../stylo/selectors" }
   324→# servo_arc = { path = "../stylo/servo_arc" }
   325→# stylo = { path = "../stylo/style" }
   326→# stylo_atoms = { path = "../stylo/stylo_atoms" }
   327→# stylo_dom = { path = "../stylo/stylo_dom" }
   328→# stylo_malloc_size_of = { path = "../stylo/malloc_size_of" }
   329→# stylo_static_prefs = { path = "../stylo/stylo_static_prefs" }
   330→# stylo_traits = { path = "../stylo/style_traits" }
   331→#
   332→# Or for WebRender:
   333→#
   334→# [patch."https://github.com/servo/webrender"]
   335→# webrender = { path = "../webrender/webrender" }
   336→# webrender_api = { path = "../webrender/webrender_api" }
   337→# wr_malloc_size_of = { path = "../webrender/wr_malloc_size_of" }
   338→#
   339→# Or for another Git dependency:
   340→#
   341→# [patch."https://github.com/servo/<repository>"]
   342→# <crate> = { path = "/path/to/local/checkout" }
   343→#
