[workspace]
resolver = "2"
members = [
    "components/media/examples",
    "components/xpath",
    "ports/servoshell",
    "tests/unit/*",
]
default-members = ["ports/servoshell"]
exclude = [".cargo", "support/crown"]

[workspace.package]
